{
  "name": "Dust & Glory: Wild West RPG",
  "description": "A browser-based idle RPG set in the American Wild West. Manage your gunslinger, equip gear in a paper-doll view, and embark on AI-narrated expeditions.",
  "requestFramePermissions": []
}

export type Slot = 'Hat' | 'Revolver' | 'Rifle' | 'Poncho' | 'Boots' | 'Badge' | 'Belt';

export enum ItemRarity {
  Common = 'Common',
  Uncommon = 'Uncommon',
  Rare = 'Rare',
  Epic = 'Epic',
  Legendary = 'Legendary'
}

export interface Stats {
  aim: number;
  reflexes: number;
  grit: number;
  charisma: number;
  stamina: number;
}

export interface Item {
  id: string;
  name: string;
  slot: Slot;
  rarity: ItemRarity;
  stats: Partial<Stats>;
  description: string;
  price: number;
}

export interface Character {
  name: string;
  level: number;
  exp: number;
  gold: number;
  baseStats: Stats;
  equipment: Record<Slot, Item | null>;
  inventory: (Item | null)[];
}

export type Scene = 'Saloon' | 'Sheriff' | 'Gunsmith' | 'HighNoon' | 'Character';

export interface Quest {
  id: string;
  title: string;
  difficulty: 'Easy' | 'Medium' | 'Hard';
  reward: { gold: number; exp: number };
  duration: number; // in seconds
}

import { Item, ItemRarity, Quest } from './types';

