export const QUESTS: Quest[] = [
  { id: 'q1', title: 'Protect the Stagecoach', difficulty: 'Easy', reward: { gold: 20, exp: 50 }, duration: 30 },
  { id: 'q2', title: 'Hunt the Rattlesnake Gang', difficulty: 'Medium', reward: { gold: 100, exp: 200 }, duration: 60 },
  { id: 'q3', title: 'Duel at the Midnight Train', difficulty: 'Hard', reward: { gold: 500, exp: 1000 }, duration: 120 }
];

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateQuestNarrative = async (questTitle: string, characterName: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Narrate a short, gritty Wild West story summary (3 sentences max) about ${characterName} completing a quest called "${questTitle}". Use a cinematic, western tone.`,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });
    return response.text;
  } catch (error) {
    console.error("Narrative generation failed", error);
    return "The dust settled as the task was completed. Another day in the frontier.";
  }
};

export const generateDuelNarrative = async (player: string, opponent: string, result: 'Win' | 'Loss') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Describe a quick-draw duel between ${player} and ${opponent}. ${player} ${result === 'Win' ? 'won' : 'lost'}. 2 sentences max. Gritty and intense.`,
    });
    return response.text;
  } catch (error) {
    return `The guns smoked. ${result === 'Win' ? player : opponent} was the faster draw today.`;
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'paper';
}

export const WesternButton: React.FC<ButtonProps> = ({ children, variant = 'primary', className = '', ...props }) => {
  const base = "px-6 py-2 uppercase font-bold transition-all transform hover:scale-105 active:scale-95 western-font text-sm border-2 shadow-lg ";
  const variants = {
    primary: "bg-[#8b4513] border-[#5d2e0d] text-[#ffebcd] hover:bg-[#a0522d]",
    secondary: "bg-[#2f4f4f] border-[#1a2e2e] text-[#f5f5dc] hover:bg-[#3d6b6b]",
    paper: "bg-[#e5d3b3] border-[#bda885] text-[#2c1e14] hover:bg-[#f5e6cc]"
  };

  return (
    <button className={`${base} ${variants[variant]} ${className}`} {...props}>
      {children}
    </button>
  );
};

export const BorderedCard: React.FC<{ children: React.ReactNode, className?: string, title?: string }> = ({ children, className = '', title }) => {
  return (
    <div className={`wood-bg border-4 border-[#5d4037] shadow-2xl relative ${className}`}>
      {/* Brass corners */}
      <div className="absolute -top-2 -left-2 w-6 h-6 border-t-4 border-l-4 border-[#b8860b] pointer-events-none"></div>
      <div className="absolute -top-2 -right-2 w-6 h-6 border-t-4 border-r-4 border-[#b8860b] pointer-events-none"></div>
      <div className="absolute -bottom-2 -left-2 w-6 h-6 border-b-4 border-l-4 border-[#b8860b] pointer-events-none"></div>
      <div className="absolute -bottom-2 -right-2 w-6 h-6 border-b-4 border-r-4 border-[#b8860b] pointer-events-none"></div>

      {title && (
        <div className="bg-[#5d4037] text-[#ffebcd] py-2 px-4 western-font text-center text-lg border-b-2 border-[#b8860b]">
          {title}
        </div>
      )}
      <div className="p-4">
        {children}
      </div>
    </div>
  );
};

export const StatsBar: React.FC<{ label: string, value: number, max?: number, color?: string }> = ({ label, value, max = 100, color = "bg-orange-700" }) => {
  const percentage = Math.min((value / max) * 100, 100);
  return (
    <div className="mb-3">
      <div className="flex justify-between text-xs mb-1 uppercase font-bold text-[#d2b48c]">
        <span>{label}</span>
        <span>{value}</span>
      </div>
      <div className="h-3 bg-black/40 border border-[#5d4037] rounded-full overflow-hidden">
        <div 
          className={`h-full ${color} transition-all duration-500`} 
          style={{ width: `${percentage}%` }}
        ></div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { Character, Item, Scene, Slot, Stats, Quest } from './types';
import { INITIAL_ITEMS, SHOP_ITEMS, QUESTS } from './constants';
import { WesternButton, BorderedCard, StatsBar } from './components/UI';
import { generateQuestNarrative, generateDuelNarrative } from './services/geminiService';
import { Home, Beer, ShieldCheck, Hammer, Sword, User, Package, Briefcase, Coins, Trophy } from 'lucide-react';

const GRID_SIZE = 20;

const App: React.FC = () => {
  const [character, setCharacter] = useState<Character>({
    name: 'Billy the Dev',
    level: 1,
    exp: 0,
    gold: 250,
    baseStats: {
      aim: 10,
      reflexes: 10,
      grit: 10,
      charisma: 10,
      stamina: 10
    },
    equipment: {
      Hat: null,
      Revolver: null,
      Rifle: null,
      Poncho: null,
      Boots: null,
      Badge: null,
      Belt: null
    },
    inventory: Array(GRID_SIZE).fill(null).map((_, i) => INITIAL_ITEMS[i] || null)
  });

  const [currentScene, setCurrentScene] = useState<Scene>('Character');
  const [activeQuest, setActiveQuest] = useState<{ quest: Quest; timeRemaining: number; startTime: number } | null>(null);
  const [lastNarrative, setLastNarrative] = useState<string>('');
  const [isLoadingNarrative, setIsLoadingNarrative] = useState(false);
  const [selectedInventoryIdx, setSelectedInventoryIdx] = useState<number | null>(null);

  // Total stats calculation
  const totalStats = useMemo(() => {
    const stats = { ...character.baseStats };
    Object.values(character.equipment).forEach(item => {
      if (item) {
        Object.entries(item.stats).forEach(([stat, val]) => {
          (stats as any)[stat] += val;
        });
      }
    });
    return stats;
  }, [character]);

  // Idle quest logic
  useEffect(() => {
    if (!activeQuest) return;

    const timer = setInterval(() => {
      setActiveQuest(prev => {
        if (!prev) return null;
        const remaining = Math.max(0, prev.duration - Math.floor((Date.now() - prev.startTime) / 1000));

        if (remaining === 0) {
          completeQuest(prev.quest);
          return null;
        }
        return { ...prev, timeRemaining: remaining };
      });
    }, 1000);

    return () => clearInterval(timer);
  }, [activeQuest]);

  const completeQuest = async (quest: Quest) => {
    setIsLoadingNarrative(true);
    const story = await generateQuestNarrative(quest.title, character.name);
    setLastNarrative(story);
    setIsLoadingNarrative(false);

    setCharacter(prev => ({
      ...prev,
      gold: prev.gold + quest.reward.gold,
      exp: prev.exp + quest.reward.exp
    }));
  };

  const handleEquip = (idx: number) => {
    const item = character.inventory[idx];
    if (!item) return;

    const slot = item.slot;
    const currentEquipped = character.equipment[slot];

    setCharacter(prev => {
      const newInventory = [...prev.inventory];
      newInventory[idx] = currentEquipped;

      return {
        ...prev,
        equipment: {
          ...prev.equipment,
          [slot]: item
        },
        inventory: newInventory
      };
    });
    setSelectedInventoryIdx(null);
  };

  const handleUnequip = (slot: Slot) => {
    const item = character.equipment[slot];
    if (!item) return;

    setCharacter(prev => {
      const emptyIdx = prev.inventory.findIndex(i => i === null);
      if (emptyIdx === -1) {
        alert("Inventory full!");
        return prev;
      }
      const newInventory = [...prev.inventory];
      newInventory[emptyIdx] = item;

      return {
        ...prev,
        equipment: {
          ...prev.equipment,
          [slot]: null
        },
        inventory: newInventory
      };
    });
  };

  const buyItem = (item: Item) => {
    if (character.gold < item.price) {
      alert("Not enough gold, stranger.");
      return;
    }
    const emptyIdx = character.inventory.findIndex(i => i === null);
    if (emptyIdx === -1) {
      alert("Backpack's full. Sell something first.");
      return;
    }

    setCharacter(prev => ({
      ...prev,
      gold: prev.gold - item.price,
      inventory: prev.inventory.map((slot, i) => i === emptyIdx ? { ...item, id: `${item.id}-${Date.now()}` } : slot)
    }));
  };

  const startQuest = (quest: Quest) => {
    if (activeQuest) {
      alert("You're already busy out there!");
      return;
    }
    setActiveQuest({
      quest,
      timeRemaining: quest.duration,
      startTime: Date.now()
    });
    setLastNarrative(`You set out to ${quest.title.toLowerCase()}...`);
  };

  const runDuel = async () => {
    const opponent = "Shadow Kid";
    const win = totalStats.aim + totalStats.reflexes > 40; // Simplified logic
    setIsLoadingNarrative(true);
    const story = await generateDuelNarrative(character.name, opponent, win ? 'Win' : 'Loss');
    setLastNarrative(story);
    setIsLoadingNarrative(false);

    if (win) {
      setCharacter(prev => ({ ...prev, gold: prev.gold + 100, exp: prev.exp + 50 }));
    }
  };

  return (
    <div className="min-h-screen flex flex-col md:flex-row">
      {/* Side Navigation - Signpost Style */}
      <nav className="w-full md:w-64 wood-bg border-r-4 border-[#2a1b10] flex flex-col p-4 space-y-2 z-10">
        <div className="mb-8 text-center">
          <h1 className="western-font text-3xl text-[#ffebcd] drop-shadow-lg leading-tight">
            DUST <span className="text-red-700">&</span> GLORY
          </h1>
          <div className="h-1 bg-[#b8860b] w-full mt-2"></div>
        </div>

        {[
          { id: 'Character', icon: User, label: 'Gunslinger' },
          { id: 'Saloon', icon: Beer, label: 'Saloon' },
          { id: 'Sheriff', icon: ShieldCheck, label: 'Sheriff' },
          { id: 'Gunsmith', icon: Hammer, label: 'Gunsmith' },
          { id: 'HighNoon', icon: Sword, label: 'High Noon' }
        ].map(item => (
          <button
            key={item.id}
            onClick={() => setCurrentScene(item.id as Scene)}
            className={`flex items-center space-x-3 p-4 western-font text-lg transition-all border-l-4 ${
              currentScene === item.id 
              ? 'bg-[#5d4037] border-[#b8860b] text-[#ffebcd]' 
              : 'border-transparent text-[#a0522d] hover:bg-[#4a342a] hover:text-[#d2b48c]'
            }`}
          >
            <item.icon size={24} />
            <span>{item.label}</span>
          </button>
        ))}

        <div className="mt-auto pt-8 border-t border-[#5d4037]">
          <div className="flex justify-between text-[#d2b48c] western-font text-sm mb-2">
            <span className="flex items-center"><Coins size={14} className="mr-1 text-yellow-500" /> {character.gold}</span>
            <span className="flex items-center"><Trophy size={14} className="mr-1 text-blue-400" /> LVL {character.level}</span>
          </div>
          <StatsBar label="EXP" value={character.exp % 1000} max={1000} color="bg-blue-600" />
        </div>
      </nav>

      {/* Main Game Area */}
      <main className="flex-1 leather-bg relative overflow-y-auto p-4 md:p-8">

        {/* Active Narrative Feedback Overlay */}
        {(lastNarrative || isLoadingNarrative) && (
          <div className="mb-6 animate-in fade-in slide-in-from-top duration-500">
            <BorderedCard className="paper-bg p-6">
              <h3 className="western-font text-xl mb-2 border-b border-[#2c1e14]/20 pb-1">Tale of the Trail</h3>
              <p className="typewriter-font text-lg">
                {isLoadingNarrative ? "Consulting the desert spirits..." : lastNarrative}
              </p>
              {activeQuest && (
                <div className="mt-4 flex items-center">
                  <div className="flex-1 h-2 bg-black/10 rounded-full mr-4 overflow-hidden">
                    <div 
                      className="h-full bg-orange-900 transition-all" 
                      style={{ width: `${(activeQuest.timeRemaining / activeQuest.quest.duration) * 100}%` }}
                    ></div>
                  </div>
                  <span className="typewriter-font text-sm">{activeQuest.timeRemaining}s left</span>
                </div>
              )}
            </BorderedCard>
          </div>
        )}

        {/* Scene Components */}
        <div className="max-w-6xl mx-auto h-full">
          {currentScene === 'Character' && (
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 h-full">
              {/* Paper Doll View */}
              <div className="flex flex-col items-center">
                <h2 className="western-font text-4xl mb-8 text-[#ffebcd]">The Gunslinger</h2>
                <div className="relative w-80 h-[500px] border-4 border-[#5d2e0d] wood-bg rounded-lg shadow-2xl p-4 flex flex-col items-center">
                  <img src="https://picsum.photos/seed/gunslinger/200/400" className="opacity-30 mix-blend-multiply absolute inset-0 w-full h-full object-cover rounded" alt="Silhouette" />

                  {/* Equipment Slots Grid */}
                  <div className="relative z-10 w-full h-full grid grid-cols-3 gap-2">
                    {/* Top Row: Hat */}
                    <div className="col-start-2 flex justify-center">
                      <EquipmentSlot 
                        slot="Hat" 
                        item={character.equipment.Hat} 
                        onUnequip={() => handleUnequip('Hat')} 
                      />
                    </div>
                    {/* Middle Row: Weapons & Badge */}
                    <div className="col-start-1 row-start-2">
                       <EquipmentSlot 
                        slot="Revolver" 
                        item={character.equipment.Revolver} 
                        onUnequip={() => handleUnequip('Revolver')} 
                      />
                    </div>
                    <div className="col-start-3 row-start-2">
                       <EquipmentSlot 
                        slot="Rifle" 
                        item={character.equipment.Rifle} 
                        onUnequip={() => handleUnequip('Rifle')} 
                      />
                    </div>
                    {/* Center Row: Poncho & Badge */}
                    <div className="col-start-2 row-start-3 flex flex-col space-y-2 items-center">
                       <EquipmentSlot 
                        slot="Poncho" 
                        item={character.equipment.Poncho} 
                        onUnequip={() => handleUnequip('Poncho')} 
                      />
                       <EquipmentSlot 
                        slot="Badge" 
                        item={character.equipment.Badge} 
                        onUnequip={() => handleUnequip('Badge')} 
                      />
                    </div>
                    {/* Bottom Row: Belt & Boots */}
                    <div className="col-start-1 row-start-5">
                       <EquipmentSlot 
                        slot="Belt" 
                        item={character.equipment.Belt} 
                        onUnequip={() => handleUnequip('Belt')} 
                      />
                    </div>
                    <div className="col-start-3 row-start-5">
                       <EquipmentSlot 
                        slot="Boots" 
                        item={character.equipment.Boots} 
                        onUnequip={() => handleUnequip('Boots')} 
                      />
                    </div>
                  </div>
                </div>

                {/* Stats Panel */}
                <BorderedCard className="w-full mt-6" title="Vitals & Grit">
                  <div className="grid grid-cols-2 gap-x-6">
                    <StatsBar label="Aim" value={totalStats.aim} />
                    <StatsBar label="Reflexes" value={totalStats.reflexes} />
                    <StatsBar label="Grit" value={totalStats.grit} />
                    <StatsBar label="Charisma" value={totalStats.charisma} />
                    <StatsBar label="Stamina" value={totalStats.stamina} />
                  </div>
                </BorderedCard>
              </div>

              {/* Inventory View */}
              <div className="flex flex-col">
                 <h2 className="western-font text-4xl mb-8 text-[#ffebcd]">Saddlebags</h2>
                 <BorderedCard className="flex-1" title="Loot & Gear">
                    <div className="grid grid-cols-4 md:grid-cols-5 gap-2">
                      {character.inventory.map((item, idx) => (
                        <div 
                          key={idx}
                          onClick={() => item && setSelectedInventoryIdx(selectedInventoryIdx === idx ? null : idx)}
                          className={`aspect-square border-2 relative cursor-pointer flex items-center justify-center transition-all ${
                            selectedInventoryIdx === idx 
                            ? 'border-[#b8860b] bg-[#4a342a] shadow-[0_0_15px_#b8860b]' 
                            : 'border-[#2a1b10] bg-[#3d2b1f] hover:border-[#5d4037]'
                          }`}
                        >
                          {item ? (
                            <div className="flex flex-col items-center justify-center p-1 text-center">
                              <span className={`text-[10px] uppercase font-bold ${rarityColor(item.rarity)} mb-1`}>{item.slot}</span>
                              <span className="text-[10px] leading-tight text-[#ffebcd] font-bold">{item.name}</span>
                            </div>
                          ) : (
                            <div className="opacity-10"><Package size={24} /></div>
                          )}
                        </div>
                      ))}
                    </div>

                    {selectedInventoryIdx !== null && character.inventory[selectedInventoryIdx] && (
                      <div className="mt-6 paper-bg p-4 border-2 border-[#b8860b] animate-in zoom-in duration-300">
                        <div className="flex justify-between items-start mb-2">
                          <h4 className="western-font text-xl">{character.inventory[selectedInventoryIdx]!.name}</h4>
                          <span className={`text-xs px-2 py-1 western-font ${rarityColor(character.inventory[selectedInventoryIdx]!.rarity)} border`}>
                            {character.inventory[selectedInventoryIdx]!.rarity}
                          </span>
                        </div>
                        <p className="typewriter-font text-sm italic mb-3">"{character.inventory[selectedInventoryIdx]!.description}"</p>
                        <div className="flex flex-wrap gap-2 mb-4">
                          {Object.entries(character.inventory[selectedInventoryIdx]!.stats).map(([s, v]) => (
                            <span key={s} className="bg-black/10 px-2 py-1 text-xs font-bold rounded">
                              +{v} {s}
                            </span>
                          ))}
                        </div>
                        <WesternButton 
                          onClick={() => handleEquip(selectedInventoryIdx!)} 
                          className="w-full"
                          variant="primary"
                        >
                          Equip to {character.inventory[selectedInventoryIdx]!.slot}
                        </WesternButton>
                      </div>
                    )}
                 </BorderedCard>
              </div>
            </div>
          )}

          {currentScene === 'Saloon' && (
            <div className="flex flex-col items-center">
               <h2 className="western-font text-5xl mb-12 text-[#ffebcd] text-center">The Rusty Horseshoe Saloon</h2>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-8 w-full">
                  <BorderedCard title="A Rumor & A Job" className="paper-bg">
                    <p className="typewriter-font mb-6 text-lg">
                      The bartender wipes a glass with a dirty rag. "If you're lookin' for trouble, it usually finds folks in the Saloon. Take a pick from the board."
                    </p>
                    <div className="space-y-4">
                      {QUESTS.map(q => (
                        <div key={q.id} className="p-4 border-2 border-[#2c1e14] bg-[#f5e6cc] flex justify-between items-center group hover:bg-[#ffebcd] transition-colors">
                          <div>
                            <h4 className="western-font text-lg">{q.title}</h4>
                            <div className="text-xs space-x-2">
                              <span className="text-red-800 font-bold uppercase">{q.difficulty}</span>
                              <span className="text-green-800 font-bold">Reward: {q.reward.gold}g | {q.reward.exp}xp</span>
                            </div>
                          </div>
                          <WesternButton 
                            variant="primary" 
                            disabled={!!activeQuest}
                            onClick={() => startQuest(q)}
                          >
                            Ride Out
                          </WesternButton>
                        </div>
                      ))}
                    </div>
                  </BorderedCard>

                  <div className="flex flex-col space-y-8">
                    <img src="https://picsum.photos/seed/saloon/600/300" className="border-4 border-[#5d4037] shadow-xl grayscale" alt="Saloon Interior" />
                    <BorderedCard title="Whiskey & Wisdom">
                      <p className="typewriter-font text-[#d2b48c] mb-4 italic">"True grit ain't about pulling the trigger fast. It's about knowing when not to."</p>
                      <WesternButton variant="secondary" className="w-full" onClick={() => alert("The bartender ignores you.")}>Buy a Round (25g)</WesternButton>
                    </BorderedCard>
                  </div>
               </div>
            </div>
          )}

          {currentScene === 'Sheriff' && (
            <div className="flex flex-col items-center">
              <h2 className="western-font text-5xl mb-12 text-[#ffebcd]">Sheriff's Office</h2>
              <div className="w-full max-w-4xl grid grid-cols-1 md:grid-cols-3 gap-6">
                {['The Red-Eyed Kid', 'Calamity Jane', 'Whisky Bill'].map((outlaw, idx) => (
