import { GoogleGenAI } from "@google/genai";

// Always use named parameter for apiKey and obtain it from process.env.API_KEY
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateQuestNarrative = async (questTitle: string, characterName: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Narrate a short, gritty Wild West story summary (3 sentences max) about ${characterName} completing a quest called "${questTitle}". Use a cinematic, western tone.`,
      config: {
        temperature: 0.8,
        topP: 0.9,
      }
    });
    // Use .text property directly (it's a getter) and provide fallback for undefined
    return response.text || "The task was done, but the desert was silent.";
  } catch (error) {
    console.error("Narrative generation failed", error);
    return "The dust settled as the task was completed. Another day in the frontier.";
  }
};

export const generateDuelNarrative = async (player: string, opponent: string, result: 'Win' | 'Loss') => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Describe a quick-draw duel between ${player} and ${opponent}. ${player} ${result === 'Win' ? 'won' : 'lost'}. 2 sentences max. Gritty and intense.`,
    });
    // Use .text property directly
    return response.text || `The guns smoked. ${result === 'Win' ? player : opponent} was the faster draw today.`;
  } catch (error) {
    return `The guns smoked. ${result === 'Win' ? player : opponent} was the faster draw today.`;
  }
};

