                            </div>
                          </div>
                          <WesternButton 
                            variant="primary" 
                            disabled={!!activeQuest}
                            onClick={() => startQuest(q)}
                          >
                            Ride Out
                          </WesternButton>
                        </div>
                      ))}
                    </div>
                  </BorderedCard>

                  <div className="flex flex-col space-y-8">
                    <img src="https://picsum.photos/seed/saloon/600/300" className="border-4 border-[#5d4037] shadow-xl grayscale" alt="Saloon Interior" />
                    <BorderedCard title="Whiskey & Wisdom">
                      <p className="typewriter-font text-[#d2b48c] mb-4 italic">"True grit ain't about pulling the trigger fast. It's about knowing when not to."</p>
                      <WesternButton variant="secondary" className="w-full" onClick={() => alert("The bartender ignores you.")}>Buy a Round (25g)</WesternButton>
                    </BorderedCard>
                  </div>
               </div>
            </div>
          )}

          {currentScene === 'Sheriff' && (
            <div className="flex flex-col items-center">
              <h2 className="western-font text-5xl mb-12 text-[#ffebcd]">Sheriff's Office</h2>
              <div className="w-full max-w-4xl grid grid-cols-1 md:grid-cols-3 gap-6">
                {['The Red-Eyed Kid', 'Calamity Jane', 'Whisky Bill'].map((outlaw, idx) => (
                  <div key={outlaw} className="paper-bg p-8 border-4 border-[#5d4037] shadow-2xl relative rotate-1 flex flex-col items-center text-center transform hover:rotate-0 transition-transform cursor-pointer">
                    <div className="absolute top-2 left-2 w-4 h-4 rounded-full bg-black/40"></div>
                    <div className="absolute top-2 right-2 w-4 h-4 rounded-full bg-black/40"></div>
                    <h3 className="western-font text-3xl font-bold mb-2">WANTED</h3>
                    <div className="w-32 h-32 bg-[#3d2b1f] mb-4 border-2 border-black flex items-center justify-center">
                       <User size={64} className="text-[#2c1e14] opacity-40" />
                    </div>
                    <h4 className="western-font text-xl mb-1">{outlaw}</h4>
                    <p className="typewriter-font text-sm uppercase font-bold mb-4">Dead or Alive</p>
                    <div className="western-font text-2xl text-red-800 mb-6">${(idx + 1) * 500} REWARD</div>
                    <WesternButton variant="primary" className="w-full">Track Down</WesternButton>
                  </div>
                ))}
              </div>
            </div>
          )}

          {currentScene === 'Gunsmith' && (
            <div className="flex flex-col">
              <h2 className="western-font text-5xl mb-12 text-[#ffebcd] text-center">O'Malley's Gunsmith</h2>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <BorderedCard title="Showroom" className="h-fit">
                  <div className="grid grid-cols-1 gap-4">
                    {SHOP_ITEMS.map(item => (
                      <div key={item.id} className="bg-[#4a342a] p-4 border border-[#b8860b] flex justify-between items-center group">
                        <div className="flex-1">
                          <div className="flex items-center space-x-2">
                             <h4 className="western-font text-lg text-[#ffebcd]">{item.name}</h4>
                             <span className={`text-[10px] ${rarityColor(item.rarity)}`}>{item.rarity}</span>
                          </div>
                          <p className="text-xs text-[#d2b48c] italic mb-1">"{item.description}"</p>
                          <div className="flex space-x-2">
                             {Object.entries(item.stats).map(([s,v]) => (
                               <span key={s} className="text-[10px] font-bold text-orange-500">+{v} {s}</span>
                             ))}
                          </div>
                        </div>
                        <div className="ml-4 text-right">
                          <div className="western-font text-[#ffebcd] mb-2">{item.price}g</div>
                          <WesternButton 
                            variant="paper" 
                            className="text-xs py-1 px-3"
                            onClick={() => buyItem(item)}
                          >
                            Buy
                          </WesternButton>
                        </div>
                      </div>
                    ))}
                  </div>
                </BorderedCard>
                <div className="flex flex-col space-y-4">
                  <img src="https://picsum.photos/seed/forge/600/400" className="border-4 border-[#b8860b] grayscale brightness-50" alt="Forge" />
                  <BorderedCard title="The Smithy">
                    <p className="typewriter-font text-[#d2b48c]">
                      Old O'Malley spits into a bucket. "You want quality? You pay for it. I don't give refunds to ghosts."
                    </p>
                  </BorderedCard>
                </div>
              </div>
            </div>
          )}

          {currentScene === 'HighNoon' && (
            <div className="flex flex-col items-center justify-center h-full min-h-[400px]">
              <h2 className="western-font text-6xl mb-4 text-[#ffebcd]">High Noon</h2>
              <p className="western-font text-xl text-red-700 mb-12">Who's the fastest in the West?</p>

              <div className="flex flex-col md:flex-row items-center space-y-8 md:space-y-0 md:space-x-24">
                {/* Player side */}
                <div className="flex flex-col items-center">
                   <div className="w-32 h-32 rounded-full border-4 border-[#b8860b] bg-[#5d4037] flex items-center justify-center overflow-hidden shadow-2xl">
                     <img src="https://picsum.photos/seed/player/128" alt="Player" />
                   </div>
                   <h3 className="western-font text-2xl mt-4">{character.name}</h3>
                   <div className="text-sm typewriter-font text-[#d2b48c]">Aim: {totalStats.aim}</div>
                </div>

                <div className="western-font text-7xl text-red-900 animate-pulse">VS</div>

                {/* Opponent side */}
                <div className="flex flex-col items-center">
                   <div className="w-32 h-32 rounded-full border-4 border-red-900 bg-[#2a1b10] flex items-center justify-center overflow-hidden shadow-2xl">
                     <img src="https://picsum.photos/seed/shadow/128" alt="Opponent" />
                   </div>
                   <h3 className="western-font text-2xl mt-4">Shadow Kid</h3>
                   <div className="text-sm typewriter-font text-[#d2b48c]">Aim: 25</div>
                </div>
              </div>

              <div className="mt-16">
                 <WesternButton 
                   variant="primary" 
                   className="text-2xl px-12 py-4 shadow-[0_0_50px_rgba(184,134,11,0.3)]"
                   onClick={runDuel}
                   disabled={isLoadingNarrative}
                 >
                   {isLoadingNarrative ? "DRAWING..." : "DRAW!"}
                 </WesternButton>
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Floating Status / Inventory Bar (Mobile Friendly) */}
      <footer className="md:hidden sticky bottom-0 w-full wood-bg border-t-2 border-[#b8860b] p-3 flex justify-between items-center z-20">
         <div className="flex items-center space-x-2 text-[#ffebcd] western-font text-sm">
           <Coins size={16} className="text-yellow-500" />
           <span>{character.gold}g</span>
         </div>
         <WesternButton onClick={() => setCurrentScene('Character')} className="py-1 px-4 text-xs" variant="secondary">Backpack</WesternButton>
      </footer>
    </div>
  );
};

const EquipmentSlot: React.FC<{ slot: Slot, item: Item | null, onUnequip: () => void }> = ({ slot, item, onUnequip }) => {
  return (
    <div 
      className={`w-16 h-16 border-2 border-[#5d2e0d] flex items-center justify-center relative group ${item ? 'bg-[#5d4037]' : 'bg-black/20'}`}
      title={slot}
    >
      {!item && <span className="text-[8px] uppercase font-bold text-[#bda885] opacity-40">{slot}</span>}
      {item && (
        <>
          <div className="flex flex-col items-center justify-center p-1 text-center cursor-default">
            <span className="text-[8px] leading-tight text-[#ffebcd] font-bold">{item.name}</span>
          </div>
          <button 
            onClick={onUnequip}
            className="absolute -top-1 -right-1 bg-red-800 text-white w-4 h-4 rounded-full text-[8px] hidden group-hover:flex items-center justify-center"
          >
            ×
          </button>
        </>
      )}
    </div>
  );
};

const rarityColor = (r: string) => {
  switch (r) {
    case 'Common': return 'text-gray-400';
    case 'Uncommon': return 'text-green-400';
    case 'Rare': return 'text-blue-400';
    case 'Epic': return 'text-purple-400';
    case 'Legendary': return 'text-orange-400';
    default: return 'text-white';
  }
};

export default App;
